 1	import * as React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	
 4	import {
 5	  ListPageFilter,
 6	  RowFilter,
 7	  useListPageFilter,
 8	  VirtualizedTable,
 9	} from '@openshift-console/dynamic-plugin-sdk';
10	
11	import { GitOpsAppGroupData } from '../utils/gitops-types';
12	
13	import { ApplicationColumns } from './ApplicationColumns';
14	import ApplicationTableRow from './ApplicationTableRow';
15	
16	import './ApplicationList.scss';
17	
18	interface ApplicationListProps {
19	  appGroups: GitOpsAppGroupData[];
20	}
21	
22	const ApplicationList: React.FC<ApplicationListProps> = ({ appGroups }) => {
23	  const { t } = useTranslation('plugin__gitops-plugin');
24	
25	  const filters: RowFilter[] = [
26	    {
27	      filterGroupName: 'App name',
28	      type: 'name',
29	      reducer: ({ name }) => name,
30	      filter: (input, app) => {
31	        if (input.selected?.length) {
32	          return app.name.includes(input.selected);
33	        }
34	        return true;
35	      },
36	      items: [{ id: 'name', title: 'name' }],
37	    },
38	  ];
39	
40	  const [staticData, filteredData, onFilterChange] = useListPageFilter(appGroups, filters);
41	
42	  const hasSyncStatus: boolean = appGroups?.some(({ sync_status }) => sync_status) || false;
43	
44	  return (
45	    <div className="gitops-plugin__application-list">
46	      <ListPageFilter
47	        data={staticData}
48	        loaded
49	        onFilterChange={onFilterChange}
50	        nameFilterPlaceholder={t('plugin__gitops-plugin~by name')}
51	        hideLabelFilter
52	      />
53	      <VirtualizedTable<GitOpsAppGroupData>
54	        data={filteredData || []}
55	        unfilteredData={staticData || []}
56	        loaded
57	        loadError={false}
58	        columns={ApplicationColumns(hasSyncStatus)}
59	        Row={ApplicationTableRow}
60	      />
61	    </div>
62	  );
63	};
64	
65	export default ApplicationList;

